UPDATE device
device_type = #{deviceType}, manufacturer = #{manufacturer}, model = #{model}, firmware_version = #{firmwareVersion}, status = #{status}, sim_card_no = #{simCardNo}, remark = #{remark}, update_time = NOW()
WHERE id = #{id}

mapper.select:
SELECT * FROM device

    
        AND status = #{status}
    
    
        AND device_type = #{deviceType}
    
    
        AND device_no LIKE CONCAT('%', #{deviceNo}, '%')
    
    
        AND vehicle_id = #{vehicleId}
    

ORDER BY create_time DESC
LIMIT #{limit} OFFSET #{offset}
